import{_ as p,o as e,c as a,j as r,a as t,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"智力1也能学会的巨镰基础使用手册","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/智力1也能学会的巨镰基础使用手册.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/智力1也能学会的巨镰基础使用手册.md"}'),n={name:"4.资源分区/6.技艺及称号/武技类/白刃类/智力1也能学会的巨镰基础使用手册.md"};function s(o,b,d,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"智力1也能学会的巨镰基础使用手册",tabindex:"-1"},[t("智力1也能学会的巨镰基础使用手册 "),r("a",{class:"header-anchor",href:"#智力1也能学会的巨镰基础使用手册","aria-label":'Permalink to "智力1也能学会的巨镰基础使用手册"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),_('<h1 id="智力1也能学会的巨镰基础手册" tabindex="-1">智力1也能学会的巨镰基础手册 <a class="header-anchor" href="#智力1也能学会的巨镰基础手册" aria-label="Permalink to &quot;智力1也能学会的巨镰基础手册&quot;">​</a></h1><p>【智力1也能学会的巨镰基础使用手册】<br> 本技艺是让初级巨镰使用者时更加顺手而存在，因此，只是一部分使用巨镰时的动作与组合。<br> 你也可以将此技艺称呼为【夏姬八砍】</p><p>限制：使用此技艺时必须使用【巨镰】</p><p>■核心技艺</p><p>【旋转】750<br> 描述：使用时卸力，变招，格挡都离不开旋转，因此是此技艺最为基础的一点<br> 效果：你使用巨镰进行攻击/使用技艺时获得【连射】<br> 同时在你使用完一个基础招式之后可以无视条件衔接任意基础招式</p><p>【持中】500<br> 描述：使用时握在中段，长兵短使，易于变招与格挡<br> 效果：只要你持有巨镰，即使你不进行格挡依旧获得2点格挡防御</p><p>【缠身】500<br> 描述：使用时环绕周身，出其不意<br> 效果：只要你持有巨镰，你使用巨镰时被攻击者降低2点基础防御</p><p>【卸力】<br> 如果想要更好的使用巨镰，你就必须要学会卸力，<br> 当你在使用巨镰基础招式需要满足力量要求时比实际增加2点。<br> 当你在使用巨镰招式【特殊】→【丢】后回收巨镰时DC降低1点<br> 若你同时已经习得了【旋转】则回收巨镰时无需进行DC判定</p><p>■基础<br> 名称：挥<br> D+500<br> 描述：以巨镰刀刃处挥击的基础招式，是基础中的基础，与【砍】同为一切的开始<br> 动作：标准动作<br> 效果：进行一次攻击，这次攻击具有5高速，可以同时攻击范围内5个敌方<br> 特殊：若你习得【旋转】则可以连续使用【挥】，每次使用额外获得1点高速（不可叠加）</p><p>名称：砍<br> D+500<br> 描述：以巨镰刀刃大力砍下的基础招式是基础中的基础，与【挥】同为一切的开始<br> 动作：标准动作<br> 效果：进行一次攻击，这次攻击具有5破甲，同时具有贯穿效果<br> 特殊：若你习得【旋转】则可以连续使用【砍】，每次使用额外获得2点威猛（不可叠加）</p><p>名称：拉<br> 1500<br> 描述：以巨镰刀刃处将敌方/物品扯向自己的基础招式<br> 限制：必须在使用【挥】/【砍】后才能使用【拉】<br> 动作：迅捷动作<br> 效果：对上轮被【挥】/【砍】攻击过的目标进行一次拖拽，如这次拖拽己方失败则将目标已有的3点严重伤害转化为恶性伤害。</p><p>特殊1：你也可以将【拉】结合在【挥】/【砍】中使用<br> 特殊2：若你已经习得【旋转】则可以支付500升级，无需按照限制来使用</p><p>名称：扯<br> 1000<br> 描述：以巨镰刀刃进行撕扯来造成伤害的基础招式<br> 限制：必须在使用【挥】/【砍】/【刺】后才能使用【扯】<br> 动作：标准动作<br> 效果：对目标进行一次攻击，对方以强韧进行对抗，造成成功数差值点挥砍伤害</p><p>名称：撩<br> 1500<br> 描述：以巨镰刀刃由下自上攻击的基础招式<br> 限制：必须在【挥】/【砍】/【刺】后才能使用【撩】<br> 动作：标准动作<br> 对目标进行一次攻击，若此次攻击伤害大于被攻击者的体积，则每超过2点就再造成1点流血点数，正常豁免对抗。这次攻击具有C级措手不及。</p><p>特殊：若你已经习得【旋转】则可以支付1000升级，无需按照限制来使用</p><p>名称：刺<br> 1000<br> 描述：以巨镰尾部进行刺击的基础招式<br> 限制：必须在使用【挥】/【撩】后才能使用【刺】<br> 动作：标准动作<br> 效果：使用巨镰进行一次攻击，这次攻击获得3高速，造成穿刺伤害，在进行特殊部位攻击时减少1点特殊部位减值。<br> 特殊：若你已经习得【旋转】则可以支付500升级，无需按照限制来使用</p><p>■特殊</p><p>名称：丢<br> D+1250<br> 描述：将巨镰丢出进行攻击的能力<br> 动作：标准动作<br> 效果：使用将巨镰作为重型投掷武器使用进行一次投掷攻击，对方以反射豁免，造成差值挥砍伤害。<br> 特殊：若你习得【旋转】则巨镰获得【回力】，则可以同时攻击目标周围15m内敌方，但巨镰因回力回到手中时需要进行一次DC2/3/4/5/6的纯力量判定，每差1点则下次自己攻击获得1点减值，此减值可以降低，可以选择对自己造成1点不可豁免的冲击点数降低1点减值。</p><p>■技艺<br> 只是一些将基础招式连贯使用的技能，因为此手册又名【夏姬八砍】所以只有8种变式<br> 如果其中一个变式的过程中满足了另外一个变式，则两者的效果叠加，前提是你已经获得了这两个变式。<br> 举例：<br> 变式1是ABCD<br> 变式2是BC<br> 使用1的时候连2使用了，那么1和2的C的效果会叠加</p><p>若前一个变式的最后1个基础招式与第2个变式的第1个基础招式相同，则你在使用第2个时可以直接使用第2个基础招式起动<br> 举例：<br> 变式1，ABCD<br> 变式2，DBAC<br> 走完1的ABCD之后继续走BAC同样能吃到2的效果</p><p>【变式一】<br> D+1250<br> 将基础招式按固定顺序连贯使出<br> 限制：习得【挥】，【砍】，【拉】，【刺】<br> 将基础招式以【砍】→【拉】→【挥】→【刺】的顺序使出使出，获得以下加成<br> 【拉】：进行拖拽时额外获得2点技艺加值<br> 【挥】：额外增加1点附加成功，这是技艺加值<br> 【刺】：现在可以将刺的效果结合在其他使用标准动作的基础招式上（不包括攻击）</p><p>【变式二】<br> D+1250<br> 限制：习得【砍】，【撩】，【刺】，【挥】<br> 将基础招式以【砍】→【刺】→【撩】→【挥】的顺序使出，获得以下加成<br> 【刺】：这次攻击获得C级措手不及<br> 【撩】：这次攻击获得2点技艺加值<br> 【挥】这次攻击可以攻击以自身为圆心半径15m的圆内的敌方单位</p><p>【变式三】<br> D+1250<br> 限制：习得【挥】，【砍】，【扯】，【拉】<br> 将基础招式以【挥】→【砍】→【扯】→【拉】的顺序使出，获得以下加成<br> 【砍】：这次攻击时获得4点威猛<br> 【扯】：这次攻击同时造成1点流血异常点数<br> 【拉】：这次拖拽的同时对目标造成2点不可豁免的严重伤害</p><p>【变式四】<br> D+1250<br> 限制：习得【刺】，【砍】，【拉】<br> 将基础招式以【刺】→【砍】→【拉】的顺序使出，获得以下加成<br> 【砍】：这次攻击时会额外将3点严重伤害转为恶性伤害<br> 【拉】：这次拖拽后目标移动速度下降10点，持续1场景</p><p>【变式五】<br> D+1250<br> 限制：习得【拉】，【砍】，【撩】<br> 将基础招式以【拉】→【砍】→【撩】的顺序使出，获得以下加成<br> 【砍】：这次攻击额外增加4点威猛<br> 【撩】：这次攻击的措手不及上升为B级</p><p>【变式六】<br> C+1000<br> 限制：习得【撩】，【挥】，【砍】<br> 将基础招式以【撩】→【挥】→【砍】的顺序使出，获得以下加成<br> 【挥】这次攻击的同时你可以进行一次移动<br> 【砍】这次攻击获得接触攻击</p><p>【变式七】<br> 750<br> 限制：习得【扯】，【砍】<br> 将基础招式以【扯】→【砍】的顺序使出，获得以下加成<br> 【砍】：这次攻击获得超级贯穿</p><p>【变式八】<br> D+1250<br> 限制：习得【砍】，【扯】<br> 将基础招式以【砍】→【扯】的顺序使出，获得以下加成<br> 【扯】：这次对抗成功数的差值每有3点，对方降低1点基础/闪避防御，持续1场景</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',30)])])}const C=p(n,[["render",s]]);export{D as __pageData,C as default};
